from collections import defaultdict

class DSU:
    def __init__(self, size):
        self.parent = list(range(size + 1))
        self.rank = [0] * (size + 1)

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        x_root = self.find(x)
        y_root = self.find(y)
        if x_root == y_root:
            return
        if self.rank[x_root] < self.rank[y_root]:
            self.parent[x_root] = y_root
        else:
            self.parent[y_root] = x_root
            if self.rank[x_root] == self.rank[y_root]:
                self.rank[x_root] += 1

def solve(c: int, connections: list[list[int]], queries: list[list[int]]) -> list[int]:
    dsu = DSU(c)
    for u, v in connections:
        dsu.union(u, v)

    components = defaultdict(list)
    for i in range(1, c + 1):
        root = dsu.find(i)
        components[root].append(i)

    componentData = {}
    for root in components:
        sorted_list = sorted(components[root])
        current_min = sorted_list[0]
        componentData[root] = [sorted_list, current_min]

    online = [True] * (c + 1)
    result = []

    for type_q, x in queries:
        if type_q == 1:
            if online[x]:
                result.append(x)
            else:
                root = dsu.find(x)
                sorted_list, current_min = componentData[root]
                if current_min == -1:
                    result.append(-1)
                else:
                    result.append(current_min)
        else:
            online[x] = False
            root = dsu.find(x)
            sorted_list, current_min = componentData[root]
            if x == current_min:
                new_min = -1
                for station in sorted_list:
                    if online[station]:
                        new_min = station
                        break
                componentData[root][1] = new_min

    return result
