function solve(c, connections, queries) {
    class DSU {
        constructor(size) {
            this.parent = Array(size + 1).fill(0).map((_, i) => i);
            this.rank = Array(size + 1).fill(0);
        }
        find(x) {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }
        union(x, y) {
            const xRoot = this.find(x);
            const yRoot = this.find(y);
            if (xRoot === yRoot) return;
            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot] += 1;
                }
            }
        }
    }

    const dsu = new DSU(c);
    for (const [u, v] of connections) {
        dsu.union(u, v);
    }

    const components = new Map();
    for (let i = 1; i <= c; i++) {
        const root = dsu.find(i);
        if (!components.has(root)) {
            components.set(root, []);
        }
        components.get(root).push(i);
    }

    const componentData = new Map();
    for (const [root, stations] of components.entries()) {
        stations.sort((a, b) => a - b);
        componentData.set(root, { sorted: stations, current_min: stations[0] });
    }

    const online = new Array(c + 1).fill(true);
    const result = [];

    for (const [type, x] of queries) {
        if (type === 1) {
            if (online[x]) {
                result.push(x);
            } else {
                const root = dsu.find(x);
                const comp = componentData.get(root);
                if (comp.current_min === -1) {
                    result.push(-1);
                } else {
                    result.push(comp.current_min);
                }
            }
        } else {
            online[x] = false;
            const root = dsu.find(x);
            const comp = componentData.get(root);
            if (x === comp.current_min) {
                let new_min = -1;
                for (const station of comp.sorted) {
                    if (online[station]) {
                        new_min = station;
                        break;
                    }
                }
                comp.current_min = new_min;
            }
        }
    }

    return result;
