from collections import defaultdict

class DSU:
    def __init__(self, size):
        self.parent = list(range(size + 1))
        self.rank = [0] * (size + 1)

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        x_root = self.find(x)
        y_root = self.find(y)
        if x_root == y_root:
            return
        if self.rank[x_root] < self.rank[y_root]:
            self.parent[x_root] = y_root
        else:
            self.parent[y_root] = x_root
            if self.rank[x_root] == self.rank[y_root]:
                self.rank[x_root] += 1

def solve(c: int, connections: list[list[int]], queries: list[list[int]]) -> list[int]:
    dsu = DSU(c)
    for u, v in connections:
        dsu.union(u, v)

    components = defaultdict(list)
    for i in range(1, c + 1):
        root = dsu.find(i)
        components[root].append(i)

    component_data = {}
    for root in components:
        stations = sorted(components[root])
        component_data[root] = {'sorted': stations, 'current_min': stations[0]}

    online = [True] * (c + 1)
    result = []

    for query in queries:
        type_q, x = query
        if type_q == 1:
            if online[x]:
                result.append(x)
            else:
                root = dsu.find(x)
                comp = component_data[root]
                if comp['current_min'] == -1:
                    result.append(-1)
                else:
                    result.append(comp['current_min'])
        else:
            online[x] = False
            root = dsu.find(x)
            comp = component_data[root]
            if comp['current_min'] == x:
                new_min = -1
                for station in comp['sorted']:
                    if online[station]:
                        new_min = station
                        break
                comp['current_min'] = new_min

    return result
